const fs = require('fs');
const path = require('path');
const _ = require('lodash');

const {builder: builderConfig} = new (require('../../lib/config'));
const Environment = new (require('../../lib/environment.js'));

const builderPath = builderConfig.path;

const targetEnvPath = path.join(builderPath.env, Environment.targetFileName);
const sourceEnvPath = path.join(builderPath.env, Environment.sourceFileName);

require('shelljs/global');

/**
 * target(dev/prod/test 등) 변수들을 포함하는 파일을 주입시킨다.
 */
class InjectTargetFilePlugin{

    constructor({
    } = {}){}
    apply(compiler){

        compiler.plugin('compile', function(){

            if (fs.existsSync(targetEnvPath)){
                cp(targetEnvPath, sourceEnvPath);
            }
        });

        compiler.plugin('emit', function(compilation, callback){

            rm('-rf', sourceEnvPath);

            callback();
        });
    };
}

module.exports = InjectTargetFilePlugin;